%dw 2.0
output application/java
fun tryRead(s) = if (s == null or (trim(s as String)) == "") null
  else (dw::Runtime::try(() -> read(s as String, "application/json")).result default null)
var ut = trim((vars.userText default "") as String)
var i = ut indexOf "{"
var j = ut lastIndexOf "}"
var outer = if (i >= 0 and j > i) (tryRead(ut[i to j])) else null
var innerStr = if (outer == null) null else ((outer."input" default outer.text default outer."parts[0].text" default outer.message default null))
var inner =
  if (outer == null) null
  else if (innerStr != null and (innerStr is String)) (tryRead(innerStr as String))
  else outer
---
if (inner != null and ((inner.partNumber default null) != null or (inner.incidentId default null) != null or (inner.supplierGoldenId default null) != null)) inner else null

%dw 2.0
output application/java
var b = vars.brokerJson default {}
---
{
  scope: "legal", mode: "execute",
  entities: {
    supplierName:     (b.supplierName default null),
    supplierGoldenId: (b.supplierGoldenId default null),
    partNumber:       (b.partNumber default null),
    incidentId:       (b.incidentId default null),
    quantity:         (b.quantity default null)
  },
  rawMessage: (b.reason default (vars.userText default "")) as String
}

%dw 2.0
output application/java
fun extractJson(s) = do {
  var t = trim(s default "")
  var noFence = (t replace /```(json)?/ with "") replace "```" with ""
  var i = noFence indexOf "{"
  var j = noFence lastIndexOf "}"
  ---
  if (i >= 0 and j > i) (noFence[i to j]) else "{}"
}
// LLM 出力が不正/途中切れ JSON でも落ちないよう try で包む。 失敗時は {} にフォールバック。
fun safeReadJson(s) =
  if (s == null or (trim(s as String)) == "") {}
  else (dw::Runtime::try(() -> read(extractJson(s as String), "application/json")).result default {})
var resp =
  if (payload == null) {}
  else if (payload is Binary) (dw::Runtime::try(() -> read(payload as String {encoding: "UTF-8"}, "application/json")).result default {})
  else if (payload is String) (dw::Runtime::try(() -> read(payload as String, "application/json")).result default {})
  else payload
var raw = ((resp.choices default [])[0].message.content default "{}") as String
var obj = safeReadJson(raw)
// 決定論バックフィル: userText から正規表現で確実に拾える値を LLM が null にした時だけ補う。
var ut = (vars.userText default "") as String
fun firstMatch(re) = do { var m = (ut scan re) --- if (sizeOf(m) > 0) m[0][0] else null }
var rxPart = firstMatch(/P-\d{4}-[A-Z0-9]+-\d+/)
var rxInc  = firstMatch(/INC-[0-9A-Za-z-]+/)
var rxGid  = firstMatch(/G-[A-Z0-9-]+/)
var rxQty  = do { var m = (ut scan /(\d+)\s*(台|個|pcs|units?)/) --- if (sizeOf(m) > 0) (m[0][1]) else null }
var le = (obj.entities default {})
var ents = le ++
  (if ((le.partNumber       default null) == null and rxPart != null) { partNumber: rxPart } else {}) ++
  (if ((le.incidentId       default null) == null and rxInc  != null) { incidentId: rxInc } else {}) ++
  (if ((le.supplierGoldenId default null) == null and rxGid  != null) { supplierGoldenId: rxGid } else {}) ++
  (if ((le.quantity         default null) == null and rxQty  != null) { quantity: (rxQty as Number) } else {})
---
{
  scope:      (obj.scope default "legal") as String,
  mode:       (obj.mode default "advise") as String,
  entities:   ents,
  rawMessage: (obj.rawMessage default ((vars.userText default "") as String)) as String
}

%dw 2.0
output application/java
var r = (vars.toolResult.result default vars.toolResult default {})
var gid = if ((r.matched default false) == true) (r.supplier.goldenId default null) else null
---
vars.intent ++ { entities: (vars.intent.entities default {}) ++ (if (gid != null) { supplierGoldenId: gid } else {}) }

%dw 2.0
output application/java
var e = vars.intent.entities default {}
---
{
  supplierGoldenId: e.supplierGoldenId,
  partNumber:       (e.partNumber default "") as String,
  incidentId:       e.incidentId
} ++ (if (e.quantity != null) { quantity: e.quantity } else {})
  ++ { reason: (vars.intent.rawMessage default "") as String }

